import {
  DateInput as DateInputPrimitive,
  type DateInputDateValue,
  useDateInput,
  useDateInputContext,
} from '@ark-ui/react/date-input';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './DateInput.module.css';

const DateInputRoot = forwardRef<
  ComponentRef<typeof DateInputPrimitive.Root>,
  ComponentProps<typeof DateInputPrimitive.Root> & DateInputFormProps
>(function DateInputRoot({ asChild, children, className, names, ...props }, ref) {
  return (
    <DateInputPrimitive.Root
      ref={ref}
      data-slot="date-input-root"
      className={clsx(styles.root, normalizeClassName(className))}
      asChild={asChild}
      {...props}
    >
      {withHiddenInputs(children, asChild, names)}
    </DateInputPrimitive.Root>
  );
});

const DateInputRootProvider = forwardRef<
  ComponentRef<typeof DateInputPrimitive.RootProvider>,
  ComponentProps<typeof DateInputPrimitive.RootProvider> & DateInputFormProps
>(function DateInputRootProvider({ asChild, children, className, names, ...props }, ref) {
  return (
    <DateInputPrimitive.RootProvider
      ref={ref}
      data-slot="date-input-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      asChild={asChild}
      {...props}
    >
      {withHiddenInputs(children, asChild, names)}
    </DateInputPrimitive.RootProvider>
  );
});

const DateInputLabel = forwardRef<
  ComponentRef<typeof DateInputPrimitive.Label>,
  ComponentProps<typeof DateInputPrimitive.Label>
>(function DateInputLabel({ className, ...props }, ref) {
  return (
    <DateInputPrimitive.Label
      ref={ref}
      data-slot="date-input-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const DateInputControl = forwardRef<
  ComponentRef<typeof DateInputPrimitive.Control>,
  ComponentProps<typeof DateInputPrimitive.Control>
>(function DateInputControl({ className, ...props }, ref) {
  return (
    <DateInputPrimitive.Control
      ref={ref}
      data-slot="date-input-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const DateInputSegmentGroup = forwardRef<
  ComponentRef<typeof DateInputPrimitive.SegmentGroup>,
  ComponentProps<typeof DateInputPrimitive.SegmentGroup>
>(function DateInputSegmentGroup({ className, ...props }, ref) {
  return (
    <DateInputPrimitive.SegmentGroup
      ref={ref}
      data-slot="date-input-segment-group"
      className={clsx(styles.segmentGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const DateInputSegment = forwardRef<
  ComponentRef<typeof DateInputPrimitive.Segment>,
  ComponentProps<typeof DateInputPrimitive.Segment>
>(function DateInputSegment({ className, ...props }, ref) {
  return (
    <DateInputPrimitive.Segment
      ref={ref}
      data-slot="date-input-segment"
      className={clsx(styles.segment, normalizeClassName(className))}
      {...props}
    />
  );
});

const DateInputSegments = forwardRef<
  ComponentRef<typeof DateInputPrimitive.SegmentGroup>,
  Omit<ComponentProps<typeof DateInputPrimitive.SegmentGroup>, 'asChild' | 'children'>
>(function DateInputSegments(props, ref) {
  return (
    <DateInputSegmentGroup ref={ref} {...props}>
      <DateInputPrimitive.SegmentContext>
        {(segment) => <DateInputSegment segment={segment} />}
      </DateInputPrimitive.SegmentContext>
    </DateInputSegmentGroup>
  );
});

type DateInputFormProps = {
  names?: readonly string[];
};

function withHiddenInputs(
  children: ReactNode,
  asChild: boolean | undefined,
  names: readonly string[] | undefined,
) {
  const hiddenInputs = <DateInputFormInputs names={names} />;

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInputs}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInputs);
}

function DateInputFormInputs({ names }: DateInputFormProps) {
  const dateInput = useDateInputContext();
  const inputCount = Math.max(dateInput.displayValues.length, names?.length ?? 0, 1);

  return (
    <>
      {Array.from({ length: inputCount }, (_, index) => (
        <DateInputPrimitive.HiddenInput
          key={index}
          index={index}
          name={names?.[index]}
          data-slot="date-input-hidden-input"
        />
      ))}
    </>
  );
}

function DateInputSeparator({
  className,
  'aria-hidden': ariaHidden = true,
  role = 'presentation',
  ...props
}: ComponentProps<'span'>) {
  return (
    <span
      data-slot="date-input-separator"
      aria-hidden={ariaHidden}
      role={role}
      className={clsx(styles.separator, normalizeClassName(className))}
      {...props}
    />
  );
}

const DateInput = Object.assign(DateInputRoot, {
  Root: DateInputRoot,
  RootProvider: DateInputRootProvider,
  Label: DateInputLabel,
  Control: DateInputControl,
  SegmentGroup: DateInputSegmentGroup,
  Segment: DateInputSegment,
  Segments: DateInputSegments,
  Separator: DateInputSeparator,
  Context: DateInputPrimitive.Context,
  SegmentContext: DateInputPrimitive.SegmentContext,
});

export { DateInput, type DateInputDateValue, useDateInput, useDateInputContext };

@layer ui.components {
  .root {
    display: inline-flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--date-input-gap, var(--spacing-1));
    width: var(--date-input-width, 100%);
    max-width: var(--date-input-max-width, none);

    &[data-disabled] {
      opacity: var(--date-input-disabled-opacity, var(--opacity-disabled));
    }
  }

  .label {
    color: var(--date-input-label-color, var(--color-foreground));
    font-size: var(--date-input-label-font-size, var(--text-sm));
    font-weight: var(--date-input-label-font-weight, var(--weight-medium));
    line-height: var(--date-input-label-line-height, var(--line-height-text-sm));
  }

  .control {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    width: var(--date-input-control-width, 100%);
    min-height: var(--date-input-control-height, var(--size-md));
    border: var(--date-input-border-width, var(--border-width-sm))
      var(--date-input-border-style, solid) var(--date-input-border-color, var(--color-border));
    border-radius: var(--date-input-radius, var(--radius-md));
    padding: var(--date-input-padding-y, var(--spacing-1)) var(--date-input-padding-x, 0.75rem);
    background-color: var(--date-input-bg, var(--color-background));
    color: var(--date-input-color, var(--color-foreground));
    outline: var(
        --date-input-focus-ring-width,
        var(--date-input-border-width, var(--border-width-sm))
      )
      solid transparent;
    outline-offset: var(--date-input-focus-ring-offset, -1px);
    transition:
      border-color var(--date-input-transition, var(--transition-default)),
      outline-color var(--date-input-transition, var(--transition-default)),
      opacity var(--date-input-transition, var(--transition-default));

    &:focus-within,
    &[data-focus] {
      outline-color: var(--date-input-focus-ring-color, var(--color-ring));
    }

    &[data-invalid] {
      border-color: var(--date-input-border-color-invalid, var(--color-destructive));

      &:focus-within,
      &[data-focus] {
        outline-color: var(--date-input-border-color-invalid, var(--color-destructive));
      }
    }

    &[data-disabled] {
      pointer-events: none;
    }
  }

  .segmentGroup {
    display: inline-flex;
    align-items: center;
    gap: var(--date-input-segment-gap, var(--border-width-md));
    font-variant-numeric: tabular-nums;
  }

  .segment {
    min-width: var(--date-input-segment-min-width, 2ch);
    border-radius: var(--date-input-segment-radius, var(--radius-sm));
    padding: var(--date-input-segment-padding-y, 0)
      var(--date-input-segment-padding-x, var(--spacing-1));
    color: var(--date-input-segment-color, currentColor);
    font: inherit;
    line-height: var(--date-input-segment-line-height, var(--line-height-text-md));
    text-align: center;
    outline: 0;
    cursor: text;
    transition:
      background-color var(--date-input-transition, var(--transition-default)),
      color var(--date-input-transition, var(--transition-default));

    &[data-placeholder-shown] {
      color: var(--date-input-placeholder-color, var(--color-muted-foreground));
    }

    &:focus-visible {
      background-color: var(
        --date-input-segment-bg-focus,
        color-mix(in oklab, var(--color-ring) 18%, transparent)
      );
      color: var(--date-input-segment-color-focus, var(--color-foreground));
    }

    &:is([data-readonly], [data-disabled]) {
      cursor: default;
    }

    &[data-type='literal'] {
      min-width: auto;
      padding-inline: 0;
      background: transparent;
      box-shadow: none;
      color: var(--date-input-separator-color, var(--color-muted-foreground));
      pointer-events: none;
    }
  }

  .separator {
    color: var(--date-input-separator-color, var(--color-muted-foreground));
    user-select: none;
  }
}
